21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	export function quote(
30	  _customer: Customer,
31	  items: Item[],
32	  _options: QuoteOptions = {},
33	): QuoteResult {
34	  const type = items[0]?.type;
35	  const basePremium = basePremiumByType[type ?? ""];
36	  const premium = items.length === 0 ? 5 : 0;
37	  return { basePremium, premium };
38	}
